var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"몇 시간 뒤","JPN":"数時間後","ENG":"A few hours later","TWN":"幾小時後","SCN":"几小时后","DEU":"A few hours later","FRA":"A few hours later"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 ~ 로터스 관리 경계 구역\\n<color=#ffd34c>CSE LV.2</color>","JPN":"シャレード～ロータス管理警戒区域\\n<color=#ffd34c>CSE LV.2</color>","ENG":"[[","TWN":"查雷德-洛德斯管理警戒區\\n<color=#ffd34c>CSE Lv.2</color>","SCN":"查雷德-洛德斯管理警戒区\\n<color=#ffd34c>CSE Lv.2</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"대장도 참 너무한다니까~","JPN":"隊長もひどいんだから。","ENG":"How can Commander do this to me?","TWN":"隊長也真是太過分了～"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임인지, 뭔지 한껏 달아오르게 하더니. 결국 지수만 홀랑 데려가 버렸잖아.","JPN":"クリフォトゲームとか何とかで盛り上がらせておいて、結局シノだけ連れて行っちゃって。","ENG":"He got all excited about the Qliphoth Game or whatever it's called, then only took Jisoo with him.","TWN":"逆卡巴拉遊戲什麼的搞得大家熱血沸騰，結果只把智秀一個人帶走了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쯧. 덕분에 이런 지루한 일이나 맡게 되고 말이야.","JPN":"おかげでこっちはこんな退屈な仕事をやる羽目になったし。","ENG":"Tsk. Thanks to that, I'm stuck with all the boring work.","TWN":"嘖，結果讓我接了這種無聊的工作。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"배역을 가리는 배우는 바람직하지 못한 법이죠.","JPN":"立派な俳優は与えられた役に文句を言わないものです。","ENG":"An actress should not complain about the role she gets.","TWN":"挑角色的演員可不是什麼好演員。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"늑대에게 있어서 당신은 이미 죽은 사람.","JPN":"オオカミにとってあなたはすでに死んだ人。","ENG":"To the Wolf, you are already dead.","TWN":"在狼的眼中，你已經是個死人了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"만에 하나 당신 모습이 늑대에게 노출된다면, 불필요한 변수가 발생할지도 모르니까요.","JPN":"万が一あなたの存在がオオカミの目についてしまったら、不必要な変数が増えますから。","ENG":"And if the Wolf somehow sees you, unnecessary variables may occur.","TWN":"萬一你的身影被狼發現，可能會引起不必要的變數。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대장님은 그런 변수를 미연에 방지하기 위해, 지수 씨를 데려간 거예요.","JPN":"隊長はその可能性を防ぐため、シノさんを連れて行ったのですよ。","ENG":"Commander took Jisoo with him to prevent those variables from happening.","TWN":"為了預防這種情況，隊長才只帶走了智秀。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그딴 건 나도 알고 있거든? 잘난 척하지 말아줄래?","JPN":"そんなのあたしだって知ってるけど？　偉そうに説教するのやめてくれる？","ENG":"I know that! So will you stop acting all high and mighty in front of me?","TWN":"那種事我也知道！別自以為是了好嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그래서? 얼마나 더 가야 하는 건데?","JPN":"で、あとどれぐらい行けばいいの？","ENG":"So? How much further do we have to go?","TWN":"所以呢？還要走多久？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"거의 다 왔습니다. 우리는 이미 <color=#ffd34c>달</color>의 영향력 아래에요.","JPN":"もうすぐです。私たちはすでに<color=#ffd34c>月</color>の影響下にいます。","ENG":"We're almost there. We are already under the <color=#ffd34c>moon's</color> influence.","TWN":"快到了。我們已經在<color=#ffd34c>月亮</color>的影響範圍內了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그 말만 벌써 세 번째라고. 애초에 이렇게 해가 밝은데 무슨 달을 보겠다는 거야?","JPN":"それもう三回目だよ。そもそもこんな明るい時間に月を見るってどういうこと？","ENG":"You said that three times already. Why are we going to see the moon when the sun's shining this bright?","TWN":"你都已經說了三次了。但是太陽這麼亮，怎麼可能看到月亮呢？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그 <color=#ffd34c>세계를 만드는 법칙</color>이란 게 정말 달이랑 관련 있긴 한 거야?","JPN":"<color=#ffd34c>世界を作る法則</color>ってのは、本当に月と関係あるの？","ENG":"Does the moon even have anything to do with <color=#ffd34c>the law of creating a world</color>?","TWN":"那個<color=#ffd34c>創造世界的法則</color>真的會和月亮有關？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"가끔은 머리를 좀 써보도록 하세요. 리트리버.","JPN":"たまには頭を使ってみてください、レトリーバー。","ENG":"Try using that brain of yours, retriever.","TWN":"有時候也動動腦子吧，獵犬。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"한낮에 달을 볼 수 있는 방법이 전혀 없는 건 아니랍니다.","JPN":"真昼に月を見る方法はあるんですよ。","ENG":"There are still ways to see the moon in the middle of the day.","TWN":"並不是完全沒有辦法在白天看到月亮。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"옛 선인들은 모든 생명체가 달에서부터 기원했다고 주장했죠.","JPN":"昔の先人たちは、すべての生命の起源は月にあると主張していました。","ENG":"Ancient beings claimed that all living organisms originated from the moon.","TWN":"古人曾主張所有生命都起源於月亮。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금은 종교적인 이야기로 치부되지만, 과학적으로도 근거가 없는 주장은 아니에요.","JPN":"今では宗教的な話だと思われますが、科学的には根拠のない話でもないのです。","ENG":"Though it is now dismissed as part of some religion, it is not a scientifically unfounded claim.","TWN":"雖然現在被認為是宗教故事，但從科學上講，這個說法也並非毫無根據。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"오래전, 거대한 천체가 지구와 충돌하면서 떨어져 나간 파편이 달이라는 주장도 있으니까요.","JPN":"月は遠い昔、巨大な天体が地球と衝突した時飛ばされた破片だという説もありますので。","ENG":"There is also a claim that the moon was a piece of debris that fell off from the Earth when a huge celestial body collided with it long ago.","TWN":"很久以前，有人認為是一顆巨大的天體與地球相撞，脫落的碎片形成了月球。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 주장에 따르면 그렇게 생성된 달의 기조력에 의해, 지구는 조수간만의 차가 발생하고.","JPN":"その説によると、そうやって生成された月の起潮力によって地球には干満の差が発生し……","ENG":"According to that claim, the Earth's tidal difference occurred due to the moon's tidal force.","TWN":"根據這一主張，是由此生成的月球引力使地球產生了潮汐變化。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"덕분에 지구는 생명체가 탄생할 수 있는 환경을 갖추게 되었다고 하죠.","JPN":"そのおかげで地球は生命体が生まれる環境になったそうです。","ENG":"Which allowed the Earth to have an environment that was suitable for life.","TWN":"多虧了它，地球才具備了孕育生命的環境。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"선생님~? 그거 시험에 나오나요~?","JPN":"先生～？　それってテストに出ますか～？","ENG":"Miss Swan? Will this be on the test?","TWN":"老師～？這題會考嗎～？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"조용히 하세요. 본론은 아직 시작도 안 했으니까.","JPN":"お静かに。まだ本題に入ってません。","ENG":"Hush. I haven't even gotten to the main topic.","TWN":"安靜點。正題還沒開始呢。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"구 관리국의 데이터에 따르면, 달의 뒷면은 <color=#ffd34c>세피라</color>와 접촉할 가능성이 가장 높은 지점.","JPN":"旧管理局のデータによると、月の裏側は<color=#ffd34c>セフィラ</color>と接触する可能性がもっとも高い地点。","ENG":"According to the Old Administration's data, the dark side of the moon is the most likely point of contact with <color=#ffd34c>Sephira</color>.","TWN":"根據舊管理局的資料，月球背面是最有可能接觸到<color=#ffd34c>塞菲拉</color>的地點。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 잔존 세력이 숨어든 북방합의체 역시 진작부터 이 사실을 알고 있었습니다.","JPN":"残存勢力が忍び込んでいる北方合意体も、この事実には気づいています。","ENG":"The Northern Union, where the remnants of its forces have gone to hide, has known about this long since.","TWN":"那個藏匿著殘餘勢力的北方和議會也早就知道了這個事實。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};